<script setup lang="ts">import {ref}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{useAuthStore}from'@/stores/auth';import{errorMessage}from'@/api/client';const username=ref(''),password=ref(''),loading=ref(false),auth=useAuthStore(),router=useRouter();async function submit(){loading.value=true;try{await auth.login(username.value,password.value);router.push('/dashboard')}catch(e){ElMessage.error(errorMessage(e))}finally{loading.value=false}}</script>
<template><div class="login"><section class="hero"><div class="hero-content"><div class="eyebrow">REM FUTURES TESTING</div><h1>把复杂的测速链路，<br/>收拢到一个可追溯的平台。</h1><p>资源独占、自动编排、实时日志、Coco 解析与报告归档。</p><div class="flow"><span>预检</span><i></i><span>接线确认</span><i></i><span>自动执行</span><i></i><span>复核报告</span></div></div></section><section class="panel"><div class="form"><div class="logo">SL</div><h2>登录 OpenSLT</h2><p class="muted">使用管理员分配的账号进入平台</p><el-form label-position="top" @submit.prevent="submit"><el-form-item label="用户名"><el-input v-model="username" size="large" autofocus/></el-form-item><el-form-item label="密码"><el-input v-model="password" type="password" size="large" show-password @keyup.enter="submit"/></el-form-item><el-button type="primary" size="large" :loading="loading" class="submit" @click="submit">安全登录</el-button></el-form><p class="notice">初始账号登录后请立即修改默认密码</p></div></section></div></template>
<style scoped>.login{min-height:100vh;display:grid;grid-template-columns:1.35fr 1fr;background:#fff}.hero{background:linear-gradient(135deg,rgba(8,35,43,.96),rgba(10,75,73,.91)),radial-gradient(circle at 30% 20%,#20b99e,#0d2f39);color:white;display:grid;place-items:center;padding:70px}.hero-content{max-width:650px}.eyebrow{letter-spacing:.22em;color:#61ddc5;font-size:12px;font-weight:700}.hero h1{font-size:46px;line-height:1.28;margin:22px 0}.hero p{font-size:18px;color:#b8d6d9}.flow{display:flex;align-items:center;margin-top:60px;font-size:13px}.flow i{width:46px;height:1px;background:#54767a;margin:0 10px}.panel{display:grid;place-items:center;padding:60px}.form{width:360px}.logo{width:48px;height:48px;background:#0c8674;color:white;border-radius:13px;display:grid;place-items:center;font-weight:800}.form h2{font-size:28px;margin:24px 0 8px}.form .muted{margin-bottom:32px}.submit{width:100%;background:#0d8c78;border-color:#0d8c78}.notice{text-align:center;font-size:12px;color:#94a3b8;margin-top:24px}</style>
